ValidationRule.errorConditionFormula:
AND (NOT($User.Bypass_Validation_Rules__c),CONTAINS($Label.CCCMRetrieveRecordTypeIds,
RecordType.DeveloperName),
OR(
ISPICKVAL(PRIORVALUE(Status), 'Reopened')
),
OR (
ISBLANK(TEXT(Reopening_Reason__c))
),
OR(
AND(NOT(ISBLANK(TEXT(Status))), ISCHANGED(Status))
 )
)
